import { useState, useRef } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Loader2, Camera, Landmark, ArrowLeft, Sparkles, Upload, ExternalLink } from "lucide-react";

const AddLandmark = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { user } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [name, setName] = useState("");
  const [address, setAddress] = useState("");
  const [photoFile, setPhotoFile] = useState<File | null>(null);
  const [photoPreview, setPhotoPreview] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [progress, setProgress] = useState("");
  const [existingLandmark, setExistingLandmark] = useState<{ id: string; name: string } | null>(null);

  if (!user) {
    return (
      <div className="min-h-screen pt-20 pb-12 px-4 bg-secondary/20">
        <div className="container mx-auto max-w-lg">
          <Card>
            <CardContent className="pt-8 pb-8 text-center space-y-4">
              <Landmark className="w-12 h-12 text-primary mx-auto" />
              <h2 className="text-xl font-bold">{t("addLandmark.loginRequired", "请先登录")}</h2>
              <p className="text-muted-foreground">{t("addLandmark.loginRequiredDesc", "添加景点需要登录账号")}</p>
              <Button onClick={() => navigate(`/auth?redirect=/add-landmark`)}>
                {t("common.login", "登录")}
              </Button>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  const handlePhotoSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const allowed = ["image/jpeg", "image/png", "image/webp"];
    if (!allowed.includes(file.type)) {
      toast({ title: t("addLandmark.invalidPhotoType", "仅支持 JPG、PNG、WebP 格式"), variant: "destructive" });
      return;
    }
    if (file.size > 10 * 1024 * 1024) {
      toast({ title: t("addLandmark.photoTooLarge", "图片不能超过 10MB"), variant: "destructive" });
      return;
    }
    setPhotoFile(file);
    setPhotoPreview(URL.createObjectURL(file));
  };

  const handleSubmit = async () => {
    if (!name.trim() || name.trim().length < 2) {
      toast({ title: t("addLandmark.nameRequired", "请输入景点名称（至少2个字）"), variant: "destructive" });
      return;
    }
    if (!address.trim() || address.trim().length < 2) {
      toast({ title: t("addLandmark.addressRequired", "请输入景点地址（至少2个字）"), variant: "destructive" });
      return;
    }
    if (!photoFile) {
      toast({ title: t("addLandmark.photoRequired", "请上传一张景点照片"), variant: "destructive" });
      return;
    }

    setIsSubmitting(true);
    setExistingLandmark(null);
    try {
      // Step 0: Check for duplicate
      setProgress(t("addLandmark.checkingDuplicate", "正在检查是否已有该景点..."));
      const trimmedName = name.trim();
      const { data: duplicates } = await supabase
        .from("restaurants")
        .select("id,name,name_en")
        .eq("template", "landmark")
        .or(`name.ilike.%${trimmedName}%,name_en.ilike.%${trimmedName}%`)
        .limit(1);

      if (duplicates && duplicates.length > 0) {
        setExistingLandmark({ id: duplicates[0].id, name: duplicates[0].name });
        setIsSubmitting(false);
        setProgress("");
        return;
      }

      // Step 1: Upload photo
      setProgress(t("addLandmark.uploadingPhoto", "正在上传照片..."));
      const ext = photoFile.name.split(".").pop() || "jpg";
      const fileName = `landmarks/${Date.now()}-${Math.random().toString(36).slice(2, 8)}.${ext}`;
      const { error: uploadError } = await supabase.storage
        .from("restaurant-images")
        .upload(fileName, photoFile, { contentType: photoFile.type, upsert: false });
      if (uploadError) throw uploadError;
      const { data: urlData } = supabase.storage.from("restaurant-images").getPublicUrl(fileName);
      const photoUrl = urlData.publicUrl;

      // Step 2: Call edge function
      setProgress(t("addLandmark.searchingWiki", "正在搜索百科资料并生成景点信息..."));
      const { data, error } = await supabase.functions.invoke("generate-landmark-from-wiki", {
        body: {
          name: name.trim(),
          address: address.trim(),
          photo_url: photoUrl,
          user_id: user.id,
          lang: "zh",
        },
      });

      if (error) throw error;
      if (!data?.draft_id) throw new Error("Failed to create landmark");

      toast({
        title: t("addLandmark.generateSuccess", "景点信息已生成"),
        description: t("addLandmark.generateSuccessDesc", "请查看并编辑景点信息，确认后发布"),
      });

      navigate(`/restaurant/${data.draft_id}`);
    } catch (e: any) {
      console.error("Add landmark error:", e);
      toast({
        title: t("addLandmark.error", "创建失败"),
        description: e.message || t("addLandmark.errorDesc", "请稍后重试"),
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
      setProgress("");
    }
  };

  return (
    <div className="min-h-screen pt-4 pb-12 px-4 bg-secondary/20">
      <div className="container mx-auto max-w-lg">
        <Button variant="ghost" size="sm" onClick={() => navigate("/join-us")} className="mb-4">
          <ArrowLeft className="w-4 h-4 mr-1" />
          {t("common.back", "返回")}
        </Button>

        <Card>
          <CardHeader className="text-center space-y-2">
            <div className="flex justify-center mb-2">
              <div className="p-3 rounded-full bg-primary/10">
                <Landmark className="w-8 h-8 text-primary" />
              </div>
            </div>
            <CardTitle className="text-2xl font-bold">{t("addLandmark.title", "添加景点")}</CardTitle>
            <CardDescription className="text-base">
              {t("addLandmark.description", "上传照片并填写名称和地址，AI 将自动从百科搜索信息生成景点页面")}
            </CardDescription>
          </CardHeader>

          <CardContent className="space-y-6">
            {/* Photo upload */}
            <div className="space-y-2">
              <Label>{t("addLandmark.photo", "景点照片")} *</Label>
              <input
                ref={fileInputRef}
                type="file"
                accept="image/jpeg,image/png,image/webp"
                className="hidden"
                onChange={handlePhotoSelect}
              />
              {photoPreview ? (
                <div className="relative">
                  <img src={photoPreview} alt="Preview" className="w-full h-48 object-cover rounded-lg border" />
                  <Button size="sm" variant="secondary" className="absolute bottom-2 right-2" onClick={() => fileInputRef.current?.click()}>
                    <Camera className="w-4 h-4 mr-1" />
                    {t("addLandmark.changePhoto", "换一张")}
                  </Button>
                </div>
              ) : (
                <div
                  onClick={() => fileInputRef.current?.click()}
                  className="flex flex-col items-center justify-center gap-3 h-48 border-2 border-dashed border-muted-foreground/30 rounded-lg cursor-pointer hover:border-primary/50 hover:bg-primary/5 transition-colors"
                >
                  <Upload className="w-8 h-8 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">
                    {t("addLandmark.uploadHint", "点击上传景点照片（JPG/PNG/WebP）")}
                  </span>
                </div>
              )}
            </div>

            {/* Name */}
            <div className="space-y-2">
              <Label>{t("addLandmark.name", "景点名称")} *</Label>
              <Input
                value={name}
                onChange={(e) => { setName(e.target.value); setExistingLandmark(null); }}
                placeholder={t("addLandmark.namePlaceholder", "例如：故宫、埃菲尔铁塔")}
                maxLength={100}
              />
            </div>

            {/* Address */}
            <div className="space-y-2">
              <Label>{t("addLandmark.address", "景点地址")} *</Label>
              <Input
                value={address}
                onChange={(e) => setAddress(e.target.value)}
                placeholder={t("addLandmark.addressPlaceholder", "例如：北京市东城区景山前街4号")}
                maxLength={200}
              />
              <p className="text-xs text-muted-foreground">
                {t("addLandmark.addressHint", "请填写完整地址，包含城市和国家便于精确定位")}
              </p>
            </div>

            {/* Existing landmark warning */}
            {existingLandmark && (
              <div className="bg-destructive/10 border border-destructive/20 rounded-lg p-4 space-y-2">
                <p className="text-sm font-medium text-destructive">
                  {t("addLandmark.duplicateFound", "该景点已存在")}
                </p>
                <p className="text-sm text-muted-foreground">
                  {t("addLandmark.duplicateFoundDesc", "我们已收录「{{name}}」，点击查看详情", { name: existingLandmark.name })}
                </p>
                <Button variant="outline" size="sm" onClick={() => navigate(`/restaurant/${existingLandmark.id}`)}>
                  <ExternalLink className="w-3.5 h-3.5 mr-1.5" />
                  {t("addLandmark.viewExisting", "查看景点")}
                </Button>
              </div>
            )}

            {/* Reward hint */}
            <div className="bg-primary/5 rounded-lg p-4 text-center space-y-1">
              <div className="flex items-center justify-center gap-2 text-primary font-medium">
                <Sparkles className="w-4 h-4" />
                <span>{t("addLandmark.rewardHint", "成功发布景点可获得 100 积分")}</span>
              </div>
              <p className="text-xs text-muted-foreground">
                {t("addLandmark.rewardRequirement", "需先收藏「景点百科」活动才可获得积分")}
                {" "}
                <a href="/activity/67a454b9-7c85-4b7d-bbf4-2174e27317a8" className="text-primary underline hover:no-underline">
                  {t("addLandmark.goToActivity", "前往收藏")}
                </a>
              </p>
            </div>

            {/* Submit */}
            <Button
              onClick={handleSubmit}
              disabled={isSubmitting || !name.trim() || !address.trim() || !photoFile}
              className="w-full"
              size="lg"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  {progress || t("addLandmark.generating", "AI 正在生成景点信息...")}
                </>
              ) : (
                <>
                  <Sparkles className="w-4 h-4 mr-2" />
                  {t("addLandmark.submit", "AI 生成景点")}
                </>
              )}
            </Button>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default AddLandmark;
